SELECT MAX(change_date) AS latest_change_date
FROM protein_history
WHERE protein_id = 2;

SELECT protein_id, COUNT(*) AS change_count
FROM protein_history
GROUP BY protein_id;

SELECT AVG(confidence_score) AS avg_confidence
FROM protein_interactions
WHERE protein_id_1 = 1 OR protein_id_2 = 1;

SELECT method
FROM orthology
WHERE protein_id_1 = 1 OR protein_id_2 = 1;

SELECT COUNT(*) AS orthology_count
FROM orthology
WHERE method = 'OMA Groups';

SELECT method, COUNT(DISTINCT protein_id_1) AS protein_count
FROM orthology
GROUP BY method;

SELECT DISTINCT a.protein_id
FROM access_logs a
ORDER BY a.protein_id;
